import { describe, expect, it } from "vitest";

import { cloudflarePrerenderPages } from "./cloudflare-prerender-pages.ts";
import {
  buildGeneratedRedirects,
  generatedRedirectsEndTag,
  generatedRedirectsStartTag,
  replaceGeneratedRedirectsBlock,
} from "./generate-cloudflare-redirects.ts";

describe("generate-cloudflare-redirects", () => {
  it("creates exact aliases from public prerender pages", () => {
    expect(buildGeneratedRedirects(cloudflarePrerenderPages)).toBe(
      [
        "# Generated by pnpm run generate:cloudflare-redirects.",
        "# Cloudflare SPA mode serves /index.html for unknown app routes, so",
        "# the SPA shell owns that file. These exact aliases expose prerendered",
        "# public pages without catching hashed assets.",
        "",
        "/ /_landing.html 200",
        "",
        "/about /about/index.html 200",
        "/about/ /about/index.html 200",
        "/about/index.html /about/index.html 200",
      ].join("\n"),
    );
  });

  it("replaces only the tagged generated block", () => {
    const contents = [
      "/legacy /new 301",
      generatedRedirectsStartTag,
      "/old /old.html 200",
      generatedRedirectsEndTag,
      "/external https://example.com 302",
      "",
    ].join("\n");

    expect(
      replaceGeneratedRedirectsBlock(contents, buildGeneratedRedirects(cloudflarePrerenderPages)),
    ).toBe(
      [
        "/legacy /new 301",
        generatedRedirectsStartTag,
        "# Generated by pnpm run generate:cloudflare-redirects.",
        "# Cloudflare SPA mode serves /index.html for unknown app routes, so",
        "# the SPA shell owns that file. These exact aliases expose prerendered",
        "# public pages without catching hashed assets.",
        "",
        "/ /_landing.html 200",
        "",
        "/about /about/index.html 200",
        "/about/ /about/index.html 200",
        "/about/index.html /about/index.html 200",
        generatedRedirectsEndTag,
        "/external https://example.com 302",
        "",
      ].join("\n"),
    );
  });

  it("requires the generated block tags", () => {
    expect(() => replaceGeneratedRedirectsBlock("/ /_landing.html 200\n", "")).toThrow(
      "Missing # @samebase/app-prerender-redirects:start",
    );
  });

  it("keeps Cloudflare SPA shell ownership of /index.html", () => {
    expect(() =>
      buildGeneratedRedirects([
        {
          path: "/",
          prerender: {
            enabled: true,
            outputPath: "/index.html",
          },
        },
      ]),
    ).toThrow("Cloudflare SPA mode serves that file");
  });
});
